SELECT ?person WHERE {
  ?person wdt:P39 ?office.
  ?person p:P39 [ ps:P39 ?office; pq:P131 wd:Q619 ].
}

SELECT ?person WHERE {
  ?person p:P39 [ ps:P39 ?office; pq:P131 wd:Q619 ];
}

SELECT ?person WHERE {
  ?person p:P39 [
    ps:P39 wd:Q526;
    pq:P131 wd:Q619
  ].
}

SELECT ?person WHERE {
  ?person p:P39 [
    ps:P39 wd:Q816145;
    pq:P131 wd:Q619
  ]
}

SELECT ?office WHERE {
  ?office rdfs:label ?label.
  FILTER (lang(?label) = 'en' && CONTAINS(STR(?label), "Tamil Nadu"))
  ?office wdt:P131 wd:Q619.
}

SELECT ?office WHERE {
  ?office rdfs:label ?label.
